# -*- coding: utf-8 -*-
"""
deploy_baostock.py — AI Hedge Fund 中国版 数据层换地基到 Baostock (v2.2.0)
=========================================================================
一次性部署 + 上机验证。自包含(base64),Windows 安全。

v2.1 变更:
  - ROOT 默认改为"优先当前工作目录"(避免写错项目副本)。
  - 部署前检查 baostock 是否可导入,缺失时显著提示。
  - 验证扩展到 主板/创业板/科创板/北交所 五板块 + 次新兜底。

⚠️ 前置:必须先把 baostock 装进当前 venv,否则新地基不生效:
    poetry add baostock
  (若 poetry 解析失败: poetry run pip install baostock)

用法(在你真正使用的项目目录下):
    cd E:\\stock\\ai-hedge-fund
    poetry add baostock
    poetry run python deploy_baostock.py
  路径不对可显式指定: poetry run python deploy_baostock.py "E:\\stock\\ai-hedge-fund"
"""
import base64, os, sys, shutil, datetime, traceback

# ---- ROOT 解析:argv > 当前目录(若含src) > 旧默认 ----
_DEFAULT = r"E:\AI-tool\Stock\ai-hedge-fund"
if len(sys.argv) > 1:
    ROOT = sys.argv[1]
elif os.path.isdir(os.path.join(os.getcwd(), "src", "tools")):
    ROOT = os.getcwd()
else:
    ROOT = _DEFAULT
TOOLS = os.path.join(ROOT, "src", "tools")
if not os.path.isdir(TOOLS):
    print("[FATAL] 找不到 src/tools, ROOT=" + ROOT); sys.exit(2)

print("==== 0) 目标确认 ====")
print("CWD  =", os.getcwd())
print("ROOT =", ROOT, ("  ✅ 与CWD一致" if os.path.normpath(ROOT)==os.path.normpath(os.getcwd()) else "  ⚠️ 与CWD不同,确认这是你要部署的副本!"))

# ---- baostock 前置检查 ----
try:
    import baostock as _probe_bs  # noqa
    _HAS_BS = True
    print("baostock import: OK", getattr(_probe_bs, "__version__", ""))
except Exception:
    _HAS_BS = False
    print("\n" + "!"*60)
    print("!! baostock 未安装进当前 venv —— 部署后新地基不会生效 !!")
    print("!! 请先运行:  poetry add baostock                       !!")
    print("!! (poetry 解析失败则: poetry run pip install baostock)  !!")
    print("!! 装好后重跑本脚本。下面仍会写文件,但验证会是兜底路径。   !!")
    print("!"*60 + "\n")

BACKUP = os.path.join(ROOT, "_aihf_backup_" + datetime.datetime.now().strftime("%Y%m%d_%H%M%S"))
os.makedirs(BACKUP, exist_ok=True)

def _backup(name):
    src = os.path.join(TOOLS, name)
    if os.path.isfile(src):
        shutil.copy2(src, os.path.join(BACKUP, name))
        print("  备份 " + name + " → " + BACKUP)

def _write(name, b64data):
    path = os.path.join(TOOLS, name)
    open(path, "w", encoding="utf-8", newline="\n").write(base64.b64decode(b64data).decode("utf-8"))
    print("  写入 " + name + " (" + str(os.path.getsize(path)) + " bytes)")

BSD_B64 = ""
LIC_B64 = ""
OVR_B64 = ""

print("\n==== 1) 部署文件 ====")
_write("baostock_data.py", BSD_B64)
_backup("line_items_china.py")
_write("line_items_china.py", LIC_B64)

api_path = os.path.join(TOOLS, "api_china.py")
existing = open(api_path, "r", encoding="utf-8", errors="replace").read()
if "marker:baostock_v2" in existing or "_BAOSTOCK_V2_INSTALLED" in existing:
    print("  api_china.py 已含 Baostock override, 跳过追加 (幂等)")
else:
    _backup("api_china.py")
    ovr_text = base64.b64decode(OVR_B64).decode("utf-8")
    with open(api_path, "a", encoding="utf-8", newline="\n") as f:
        f.write(ovr_text)
    print("  追加 override 到 api_china.py (+" + str(len(ovr_text.encode("utf-8"))) + " bytes)")

print("\n==== 2) 上机验证 (真 Baostock) ====")
sys.path.insert(0, ROOT)
try:
    from src.tools import baostock_data as bsd
    avail = bsd.available()
    print("baostock available:", avail)
    if not avail:
        print("[WARN] baostock 不可用 → 跳过 Baostock 直连验证 (见上方安装提示)")
    else:
        print("\n-- 板块覆盖探测 (日线行数 / 季报期数) --")
        probes = [("600519.SH","SH主板 茅台"), ("000333.SZ","SZ主板 美的"),
                  ("300308.SZ","创业板 中际旭创"), ("688019.SH","科创板 安集"),
                  ("430047.BJ","北交所 诺思兰德")]
        for tk, label in probes:
            try:
                rows = bsd.get_prices_dicts(tk, "2026-06-01", "2026-06-20")
                qs = bsd.get_quarters(tk, "2026-06-22", limit=1)
                last = rows[-1]["close"] if rows else None
                print("  %-16s %s 日线=%d 季报=%d 末收=%s" % (tk, label, len(rows), len(qs), last))
            except Exception as e:
                print("  %-16s %s 异常: %s" % (tk, label, str(e)[:80]))

        print("\n-- 600519 反推明细 --")
        qs = bsd.get_quarters("600519.SH", "2026-06-22", limit=2)
        if qs:
            m = bsd.metrics_from_block(qs[0]); li = bsd.line_items_from_block(qs[0])
            print("  报告期=%s net_margin=%s roe=%s gross=%s" % (
                qs[0].get("statDate"), m.get("net_margin"), m.get("return_on_equity"), m.get("gross_margin")))
            print("  revenue=%.1f亿 net_income=%.1f亿 assets=%.1f亿 equity=%.1f亿" % (
                (li.get("revenue") or 0)/1e8, (li.get("net_income") or 0)/1e8,
                (li.get("total_assets") or 0)/1e8, (li.get("shareholders_equity") or 0)/1e8))
            print("  FCF/capex(应None):", li.get("free_cash_flow"), li.get("capital_expenditure"))
        val = bsd.latest_valuation("600519.SH", "2026-06-22")
        print("  估值:", val, "| 市值=%.3f万亿" % ((bsd.market_cap("600519.SH","2026-06-22") or 0)/1e12))

    print("\n-- 路由层 (api_china override) --")
    from src.tools import api_china as cn
    p = cn.get_prices("600519", "2026-06-01", "2026-06-20")
    print("  cn.get_prices(600519):", len(p), "行, 末收", (p[-1].close if p else None))
    fm = cn.get_financial_metrics("600519", "2026-06-22", limit=2)
    if fm:
        print("  cn.get_financial_metrics(600519):", len(fm), "期, pe=", fm[0].price_to_earnings_ratio,
              "pb=", fm[0].price_to_book_ratio, "mc=%.3f万亿" % ((fm[0].market_cap or 0)/1e12),
              "报告期=", fm[0].report_period)
    else:
        print("  cn.get_financial_metrics(600519): 空 (baostock不可用时会走兜底, 可能空)")
    from src.tools.line_items_china import search_line_items_china
    li2 = search_line_items_china("600519", ["revenue","net_income","total_assets","free_cash_flow"], "2026-06-22", limit=2)
    if li2:
        print("  search_line_items(600519):", len(li2), "期, rev=%.1f亿" % ((li2[0].revenue or 0)/1e8), "fcf=", li2[0].free_cash_flow)
    fm2 = cn.get_financial_metrics("000333", "2026-06-22", limit=1)
    if fm2:
        print("  cn.get_financial_metrics(000333):", "pe=", fm2[0].price_to_earnings_ratio, "mc=%.0f亿" % ((fm2[0].market_cap or 0)/1e8))

    try:
        p5 = cn.get_prices("605788", "2026-06-01", "2026-06-20")
        print("\n  605788 (Baostock空→兜底):", len(p5), "行 (不崩即合格)")
    except Exception as e:
        print("  605788 兜底异常:", e)
except Exception:
    print("[验证异常]\n" + traceback.format_exc())

print("\n==== 完成 ====")
print("备份目录:", BACKUP)
print("回滚: 把备份里的 *.py 拷回 src/tools/, 并删除 api_china.py 末尾 [marker:baostock_v2] 块")
print(">>> 请把上面'上机验证'的完整输出贴回来 <<<")
